game.script:
let seconds = 0;
let animationEnabled = true;
const cameraSpeed = 3;
const input = document.querySelector("input");
const network = document.querySelector("network");
const camera = document.querySelector("#camera");
const box = document.querySelector("#box");
const boxJoint = document.querySelector("#box-joint");
const tube = document.querySelector("#tube");
const tubeJoint = document.querySelector("#tube-joint");
const ball = document.querySelector("#ball");
const status = document.querySelector("#status");
const toggle = document.querySelector("#toggle");
let cameraX = 0;
let cameraZ = 4;
const clients = new Map();
const moveKeys = ["KeyW", "KeyS", "KeyA", "KeyD"];

boxJoint.setRotationFromEuler(0, 0, -Math.PI * 0.5);
tubeJoint.setRotationFromEuler(0, 0, -Math.PI * 0.5);

function syncUi() {
  status.setText(animationEnabled ? "Rotation: on" : "Rotation: off");
  toggle.setText(animationEnabled ? "Pause rotation" : "Resume rotation");
}

syncUi();

function getClientKeys(clientId) {
  let keys = clients.get(clientId);

  if (keys === undefined) {
    keys = new Set();
    clients.set(clientId, keys);
  }

  return keys;
}

function isDown(code) {
  for (const keys of clients.values()) {
    if (keys.has(code)) {
      return true;
    }
  }

  return false;
}

function handleEvent(event) {
  if (event.name === "disconnect") {
    clients.delete(event.clientId);
    return;
  }

  if (event.name === "keyPressed") {
    getClientKeys(event.clientId).add(event.data);
    return;
  }

  if (event.name === "keyReleased") {
    getClientKeys(event.clientId).delete(event.data);
    return;
  }

  if (event.name === "toggleRotation") {
    animationEnabled = !animationEnabled;
    syncUi();
  }
}

function animateColor(shape, time, phase) {
  shape.setColor(
    0.5 + 0.5 * Math.sin(time + phase),
    0.5 + 0.5 * Math.sin(time * 1.3 + phase + 2),
    0.5 + 0.5 * Math.sin(time * 0.7 + phase + 4),
  );
}

function tickClient() {
  if (toggle.wasClicked()) {
    network.emit("toggleRotation", null);
  }

  for (const code of moveKeys) {
    if (input.wasPressed(code)) {
      network.emit("keyPressed", code);
    }

    if (input.wasReleased(code)) {
      network.emit("keyReleased", code);
    }
  }
}

function tickServer(deltaTime) {
  let event = network.pollEvent();

  while (event !== undefined) {
    handleEvent(event);
    event = network.pollEvent();
  }

  if (isDown("KeyW")) {
    cameraZ -= cameraSpeed * deltaTime;
  }
  if (isDown("KeyS")) {
    cameraZ += cameraSpeed * deltaTime;
  }
  if (isDown("KeyA")) {
    cameraX -= cameraSpeed * deltaTime;
  }
  if (isDown("KeyD")) {
    cameraX += cameraSpeed * deltaTime;
  }

  if (animationEnabled) {
    seconds += deltaTime;
  }

  camera.setPosition(cameraX, 0, cameraZ);
  camera.setRotationFromEuler(0, 0, 0);
  box.setRotationFromEuler(0, seconds * 0.9, 0);
  tube.setRotationFromEuler(0, -seconds * 1.2, seconds * 0.5);
  ball.setRotationFromEuler(seconds * 0.8, seconds * 0.6, 0);
  animateColor(box, seconds, 0);
  animateColor(tube, seconds, 1.7);
  animateColor(ball, seconds, 3.4);
}

function tick(deltaTime) {
  if (input !== null) {
    tickClient();
    return;
  }

  tickServer(deltaTime);
}
